-- Table structure for table `sip_campaign_contacts`
DROP TABLE IF EXISTS `sip_campaign_contacts`;
CREATE TABLE `sip_campaign_contacts` (
  `id` bigint unsigned NOT NULL,
  `created_at` datetime(3) DEFAULT NULL COMMENT 'Creation time',
  `updated_at` datetime(3) DEFAULT NULL COMMENT 'Update time',
  `deleted_at` datetime(3) DEFAULT NULL,
  `create_by` varchar(128) DEFAULT NULL COMMENT 'Creator',
  `update_by` varchar(128) DEFAULT NULL COMMENT 'Updater',
  `remark` varchar(128) DEFAULT NULL COMMENT 'Remark',
  `campaign_id` bigint unsigned NOT NULL,
  `phone` varchar(64) NOT NULL,
  `request_uri` varchar(256) DEFAULT NULL,
  `display` varchar(128) DEFAULT NULL,
  `caller_user` varchar(128) DEFAULT NULL,
  `caller_name` varchar(128) DEFAULT NULL,
  `status` varchar(24) NOT NULL DEFAULT 'ready',
  `priority` bigint DEFAULT '0',
  `attempt_count` bigint DEFAULT '0',
  `max_attempts` bigint DEFAULT '3',
  `next_run_at` datetime(3) DEFAULT NULL,
  `last_dial_at` datetime(3) DEFAULT NULL,
  `last_call_id` varchar(128) DEFAULT NULL,
  `correlation_id` varchar(128) DEFAULT NULL,
  `failure_reason` text,
  `variables` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_sip_campaign_contacts_deleted_at` (`deleted_at`),
  KEY `idx_sip_campaign_contacts_campaign_id` (`campaign_id`),
  KEY `idx_sip_campaign_contacts_phone` (`phone`),
  KEY `idx_sip_campaign_contacts_status` (`status`),
  KEY `idx_sip_campaign_contacts_priority` (`priority`),
  KEY `idx_sip_campaign_contacts_next_run_at` (`next_run_at`),
  KEY `idx_sip_campaign_contacts_last_dial_at` (`last_dial_at`),
  KEY `idx_sip_campaign_contacts_last_call_id` (`last_call_id`),
  KEY `idx_sip_campaign_contacts_correlation_id` (`correlation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

-- Dumping data for table `sip_campaign_contacts`

-- Table structure for table `sip_campaign_events`
DROP TABLE IF EXISTS `sip_campaign_events`;
CREATE TABLE `sip_campaign_events` (
  `id` bigint unsigned NOT NULL,
  `created_at` datetime(3) DEFAULT NULL COMMENT 'Creation time',
  `updated_at` datetime(3) DEFAULT NULL COMMENT 'Update time',
  `deleted_at` datetime(3) DEFAULT NULL,
  `create_by` varchar(128) DEFAULT NULL COMMENT 'Creator',
  `update_by` varchar(128) DEFAULT NULL COMMENT 'Updater',
  `remark` varchar(128) DEFAULT NULL COMMENT 'Remark',
  `campaign_id` bigint unsigned NOT NULL,
  `contact_id` bigint unsigned DEFAULT NULL,
  `attempt_id` bigint unsigned DEFAULT NULL,
  `call_id` varchar(128) DEFAULT NULL,
  `correlation_id` varchar(128) DEFAULT NULL,
  `type` varchar(32) NOT NULL,
  `level` varchar(16) NOT NULL,
  `message` text NOT NULL,
  `meta` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_sip_campaign_events_deleted_at` (`deleted_at`),
  KEY `idx_sip_campaign_events_campaign_id` (`campaign_id`),
  KEY `idx_sip_campaign_events_contact_id` (`contact_id`),
  KEY `idx_sip_campaign_events_attempt_id` (`attempt_id`),
  KEY `idx_sip_campaign_events_call_id` (`call_id`),
  KEY `idx_sip_campaign_events_correlation_id` (`correlation_id`),
  KEY `idx_sip_campaign_events_type` (`type`),
  KEY `idx_sip_campaign_events_level` (`level`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

-- Dumping data for table `sip_campaign_events`

-- Table structure for table `sip_campaigns`
DROP TABLE IF EXISTS `sip_campaigns`;
CREATE TABLE `sip_campaigns` (
  `id` bigint unsigned NOT NULL,
  `created_at` datetime(3) DEFAULT NULL COMMENT 'Creation time',
  `updated_at` datetime(3) DEFAULT NULL COMMENT 'Update time',
  `deleted_at` datetime(3) DEFAULT NULL,
