-- Table structure for table `tenant_roles`
DROP TABLE IF EXISTS `tenant_roles`;
CREATE TABLE `tenant_roles` (
  `id` bigint unsigned NOT NULL,
  `created_at` datetime(3) DEFAULT NULL COMMENT 'Creation time',
  `updated_at` datetime(3) DEFAULT NULL COMMENT 'Update time',
  `deleted_at` datetime(3) DEFAULT NULL,
  `create_by` varchar(128) DEFAULT NULL COMMENT 'Creator',
  `update_by` varchar(128) DEFAULT NULL COMMENT 'Updater',
  `remark` varchar(128) DEFAULT NULL COMMENT 'Remark',
  `tenant_id` bigint unsigned NOT NULL,
  `name` varchar(128) NOT NULL,
  `description` varchar(512) DEFAULT NULL,
  `is_system` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_roles_deleted_at` (`deleted_at`),
  KEY `idx_tenant_roles_tenant_id` (`tenant_id`),
  KEY `idx_tenant_roles_name` (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

